// Minimal Markdown renderer for lil-agents-win
// Supports: headings, bold, italic, inline code, code blocks, unordered lists,
// ordered lists, horizontal rules, and escapes plain text for XSS safety.
(function (global) {
  'use strict';

  function escapeHtml(str) {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function inlineRender(text) {
    // Inline code (must come before bold/italic to protect contents)
    text = text.replace(/`([^`]+)`/g, function (_, code) {
      return '<code>' + escapeHtml(code) + '</code>';
    });
    // Bold **text** or __text__
    text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');
    // Italic *text* or _text_
    text = text.replace(/\*(.+?)\*/g, '<em>$1</em>');
    text = text.replace(/_(.+?)_/g, '<em>$1</em>');
    return text;
  }

  function parse(src) {
    var lines = src.split(/\r?\n/);
    var html = '';
    var i = 0;

    function peek() { return i < lines.length ? lines[i] : null; }
    function consume() { return lines[i++]; }

    while (i < lines.length) {
      var line = peek();

      // Fenced code block
      if (/^```/.test(line)) {
        var lang = line.slice(3).trim();
        consume();
        var code = [];
        while (peek() !== null && !/^```/.test(peek())) {
          code.push(consume());
        }
        if (peek() !== null) consume(); // closing ```
        html += '<pre><code' + (lang ? ' class="language-' + escapeHtml(lang) + '"' : '') + '>' +
          escapeHtml(code.join('\n')) + '</code></pre>';
        continue;
      }

      // Horizontal rule
      if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
        consume();
        html += '<hr>';
        continue;
      }

      // Headings
      var hMatch = line.match(/^(#{1,6})\s+(.*)/);
      if (hMatch) {
        consume();
        var level = hMatch[1].length;
        html += '<h' + level + '>' + inlineRender(escapeHtml(hMatch[2])) + '</h' + level + '>';
        continue;
      }

      // Unordered list
      if (/^[-*+]\s/.test(line)) {
        html += '<ul>';
        while (peek() !== null && /^[-*+]\s/.test(peek())) {
          var item = consume().replace(/^[-*+]\s/, '');
          html += '<li>' + inlineRender(escapeHtml(item)) + '</li>';
        }
        html += '</ul>';
        continue;
      }

      // Ordered list
      if (/^\d+\.\s/.test(line)) {
        html += '<ol>';
        while (peek() !== null && /^\d+\.\s/.test(peek())) {
          var oitem = consume().replace(/^\d+\.\s/, '');
          html += '<li>' + inlineRender(escapeHtml(oitem)) + '</li>';
        }
        html += '</ol>';
        continue;
      }

      // Blank line
      if (/^\s*$/.test(line)) {
        consume();
        html += '<br>';
        continue;
      }

      // Paragraph / plain line
      var paraLines = [];
      while (peek() !== null && !/^\s*$/.test(peek()) &&
             !/^```/.test(peek()) &&
             !/^#{1,6}\s/.test(peek()) &&
             !/^[-*+]\s/.test(peek()) &&
             !/^\d+\.\s/.test(peek()) &&
             !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(peek())) {
        paraLines.push(consume());
      }
      html += '<p>' + inlineRender(escapeHtml(paraLines.join('\n'))) + '</p>';
    }

    return html;
  }

  global.lilMarked = { parse: parse };
})(typeof window !== 'undefined' ? window : this);
